211	<section
212		data-testid="integrity-panel"
213		class="shrink-0 rounded-none border border-border-line bg-bg-surface text-sm text-fg-ink dark:border-dark-border-line dark:bg-dark-bg-surface dark:text-dark-fg-ink"
214	>
215		<header class="border-b border-border-line px-4 py-2 font-semibold dark:border-dark-border-line">
216			Integrity: {issues.length}
217			{issues.length === 1 ? 'issue' : 'issues'}
218		</header>
219		<ul class="divide-y divide-border-line dark:divide-dark-border-line">
220			{#each groups as group (group.kind)}
221				{@const isOpen = expanded[group.kind] ?? false}
222				<li data-kind={group.kind}>
223					<button
224						type="button"
225						class="flex w-full items-center gap-2 px-4 py-2 text-left hover:bg-bg-canvas dark:hover:bg-dark-bg-canvas"
226						aria-expanded={isOpen}
227						data-testid={`integrity-group-${group.kind}`}
228						onclick={() => toggle(group.kind)}
229					>
230						{#if isOpen}
231							<ChevronDown class="h-4 w-4" aria-hidden="true" />
232						{:else}
233							<ChevronRight class="h-4 w-4" aria-hidden="true" />
234						{/if}
235						<span class="font-medium">{labelFor(group.kind)}</span>
236						<span class="text-fg-muted dark:text-dark-fg-muted">({group.issues.length})</span>
237					</button>
238					{#if isOpen}
239						<ul class="bg-bg-canvas px-4 pb-3 pt-1 dark:bg-dark-bg-canvas">
240							{#each group.issues as issue, idx (`${group.kind}-${idx}`)}
241								{@const repairStrategy = strategyFor(issue)}
242								{@const issueKey = issue.issueId ?? ''}
243								<li class="mt-2 flex flex-col gap-1 rounded-none bg-bg-elevated p-2 dark:bg-dark-bg-elevated">
244									<div class="flex flex-wrap items-center gap-2 font-mono text-xs">
245										{#if issue.path}
246											{@const href = docLink(issue.path)}
247											{#if href}
248												<a
249													href={href}
250													data-testid="integrity-path-link"
251													class="text-accent-lever underline hover:text-accent-lever/80 dark:text-dark-accent-lever dark:hover:text-dark-accent-lever/80"
252													>{issue.path}</a
253												>
254											{:else}
255												<span>{issue.path}</span>
256											{/if}
257										{/if}
258										{#if issue.relatedPath}
259											{@const relHref = docLink(issue.relatedPath)}
260											<span class="text-fg-muted dark:text-dark-fg-muted">↔</span>
261											{#if relHref}
262												<a
263													href={relHref}
264													data-testid="integrity-related-link"
265													class="text-accent-lever underline hover:text-accent-lever/80 dark:text-dark-accent-lever dark:hover:text-dark-accent-lever/80"
266													>{issue.relatedPath}</a
267												>
268											{:else}
269												<span>{issue.relatedPath}</span>
270											{/if}
271										{/if}
272										{#if issue.id}
273											<span
274												class="rounded-none border px-1.5 py-0.5 text-[10px] uppercase badge-status-blocked"
275												>{issue.id}</span
276											>
277										{/if}
278									</div>
279									<div class="flex items-start justify-between gap-2">
280										<p class="break-words">{issue.message}</p>
281										<button
282											type="button"
283											class="shrink-0 rounded-none border border-border-line bg-bg-elevated px-2 py-1 text-xs hover:bg-bg-surface dark:border-dark-border-line dark:bg-dark-bg-surface dark:hover:bg-dark-bg-canvas"
284											title="Copy message"
285											aria-label="Copy message"
286											onclick={(e) => copyMessage(issue, e)}
287										>
288											<Copy class="h-3 w-3" aria-hidden="true" />
289										</button>
290									</div>
291									{#if group.kind === 'duplicate_id'}
292										<button
293											type="button"
294											data-testid="integrity-copy-suggestion"
295											class="self-start rounded-none border px-2 py-1 text-xs font-medium badge-status-blocked hover:opacity-90"
296											onclick={(e) => copySuggestion(issue, e)}
297										>
298											Copy suggested unique ID
299										</button>
300									{/if}
301									{#if repairStrategy}
302										<div class="flex flex-wrap items-center gap-2 text-xs">
303											<button
304												type="button"
305												data-testid="integrity-preview-fix"
306												class="rounded-none border border-border-line bg-bg-elevated px-2 py-1 hover:bg-bg-surface dark:border-dark-border-line dark:bg-dark-bg-surface dark:hover:bg-dark-bg-canvas"
307												onclick={() => togglePreview(issue)}
308											>
309												{previewing[issueKey] ? 'Hide preview' : 'Preview fix'}
310											</button>
311											<button
312												type="button"
313												data-testid="integrity-apply-fix"
314												disabled={pending[issueKey]}
315												class="rounded-none border px-2 py-1 font-medium badge-status-blocked hover:opacity-90 disabled:opacity-50"
316												onclick={() => applyFix(issue)}
317											>
318												{pending[issueKey] ? 'Applying…' : 'Apply fix'}
319											</button>
320										</div>
321										{#if previewing[issueKey]}
322											{@const diff =
323												repairStrategy === 'REMOVE_MISSING_DEP'
324													? diffRemoveDep(issue)
325													: diffApplySuggestedID(issue, previewedSuggestions[issueKey] ?? '')}
326											<div
327												data-testid="integrity-preview-diff"
328												class="mt-1 grid gap-1 rounded-none border border-border-line bg-bg-canvas p-2 font-mono text-xs dark:border-dark-border-line dark:bg-dark-bg-canvas"
329											>
330												<div class="text-fg-muted dark:text-dark-fg-muted">Before</div>
331												<pre class="overflow-x-auto whitespace-pre-wrap text-status-blocked">{diff.before}</pre>
332												<div class="text-fg-muted dark:text-dark-fg-muted">After</div>
333												<pre class="overflow-x-auto whitespace-pre-wrap text-status-merged">{diff.after}</pre>
334											</div>
335										{/if}
336										{#if inlineErrors[issueKey]}
337											<p
338												data-testid="integrity-repair-error"
339												class="text-xs text-status-blocked"
340											>
341												{inlineErrors[issueKey]}
342											</p>
343										{/if}
344									{/if}
345									{#if group.kind === 'missing_dep' && issue.id}
346										{@const snippet = dependencyRemovalSnippet(issue)}
347										{#if snippet}
348											<div class="flex flex-wrap items-center gap-2 text-xs">
349												<span class="font-medium text-fg-muted dark:text-dark-fg-muted">
350													Remove from depends_on
351												</span>
352												<code
353													data-testid="integrity-missing-dep-snippet"
354													class="rounded-none border px-2 py-1 font-mono-code badge-status-blocked"
355													>{snippet}</code
356												>
357												<button
358													type="button"
359													class="rounded-none border border-border-line bg-bg-elevated px-2 py-1 hover:bg-bg-surface dark:border-dark-border-line dark:bg-dark-bg-surface dark:hover:bg-dark-bg-canvas"
360													title="Copy removal snippet"
361													aria-label="Copy missing dependency removal snippet"
362													onclick={(e) => copyDependencyRemovalSnippet(issue, e)}
363												>
364													<Copy class="h-3 w-3" aria-hidden="true" />
365												</button>
366											</div>
367										{/if}
368									{/if}
369								</li>
370							{/each}
371						</ul>
372					{/if}
373				</li>
374			{/each}
375		</ul>
376	</section>
